import { Box, Typography } from '@mui/material';

interface LevelBadgeProps {
  level: number;
  size?: number;
}

function getTierColor(level: number): { bg: string; border: string; label: string } {
  if (level >= 50) return { bg: '#e5e4e2', border: '#b4b4b4', label: 'Platinum' };
  if (level >= 26) return { bg: '#ffd700', border: '#daa520', label: 'Gold' };
  if (level >= 11) return { bg: '#c0c0c0', border: '#a8a8a8', label: 'Silver' };
  return { bg: '#cd7f32', border: '#a0522d', label: 'Bronze' };
}

export default function LevelBadge({ level, size = 48 }: LevelBadgeProps) {
  const tier = getTierColor(level);

  return (
    <Box
      sx={{
        width: size,
        height: size,
        borderRadius: '50%',
        background: `radial-gradient(circle at 30% 30%, ${tier.bg}, ${tier.border})`,
        border: `3px solid ${tier.border}`,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        boxShadow: `0 2px 8px ${tier.border}40`,
        position: 'relative',
      }}
      title={`Level ${level} (${tier.label})`}
    >
      <Typography
        sx={{
          fontWeight: 800,
          fontSize: size * 0.4,
          color: level >= 26 ? '#1a1a1a' : '#fff',
          lineHeight: 1,
        }}
      >
        {level}
      </Typography>
    </Box>
  );
}

