import { Box, Typography, Grid, Paper, Chip } from '@mui/material';
import { Lock, EmojiEvents } from '@mui/icons-material';

interface AchievementData {
  slug: string;
  title: string;
  description: string;
  icon: string;
  xpReward: number;
  isSecret: boolean;
  unlockedAt: string | null;
}

interface AchievementShowcaseProps {
  achievements: AchievementData[];
}

export default function AchievementShowcase({ achievements }: AchievementShowcaseProps) {
  const earned = achievements.filter((a) => a.unlockedAt);
  const visible = achievements.filter((a) => !a.isSecret || a.unlockedAt);
  const hiddenCount = achievements.filter((a) => a.isSecret && !a.unlockedAt).length;

  return (
    <Box>
      <Box display="flex" justifyContent="space-between" alignItems="center" mb={2}>
        <Typography variant="h6">Achievements</Typography>
        <Chip label={`${earned.length} / ${achievements.length}`} color="primary" size="small" />
      </Box>

      <Grid container spacing={2}>
        {visible.map((ach) => {
          const isEarned = Boolean(ach.unlockedAt);
          return (
            <Grid item xs={12} sm={6} md={4} key={ach.slug}>
              <Paper
                sx={{
                  p: 2,
                  opacity: isEarned ? 1 : 0.5,
                  filter: isEarned ? 'none' : 'grayscale(100%)',
                  border: isEarned ? '2px solid #ffd700' : '1px solid #e0e0e0',
                  transition: 'all 0.3s',
                  '&:hover': { transform: 'translateY(-2px)', boxShadow: 3 },
                }}
              >
                <Box display="flex" alignItems="center" gap={1} mb={1}>
                  <EmojiEvents sx={{ color: isEarned ? '#ffd700' : '#bdbdbd' }} />
                  <Typography variant="subtitle2" fontWeight={700}>
                    {ach.title}
                  </Typography>
                </Box>
                <Typography variant="body2" color="text.secondary">
                  {ach.description}
                </Typography>
                {isEarned && (
                  <Typography variant="caption" color="text.secondary" mt={1} display="block">
                    Unlocked {new Date(ach.unlockedAt!).toLocaleDateString()}
                  </Typography>
                )}
              </Paper>
            </Grid>
          );
        })}
      </Grid>

      {hiddenCount > 0 && (
        <Box display="flex" alignItems="center" gap={1} mt={2} color="text.secondary">
          <Lock fontSize="small" />
          <Typography variant="body2">
            {hiddenCount} secret achievement{hiddenCount > 1 ? 's' : ''} remaining
          </Typography>
        </Box>
      )}
    </Box>
  );
}

import { Box, Typography, Chip, Tooltip } from '@mui/material';
import { LocalFireDepartment, AcUnit } from '@mui/icons-material';

interface StreakDisplayProps {
  currentStreak: number;
  longestStreak: number;
  freezesRemaining: number;
  activityDays: string[];  // ISO date strings of active days
}

function getHeatmapColor(count: number): string {
  if (count === 0) return '#ebedf0';
  if (count === 1) return '#9be9a8';
  if (count <= 3) return '#40c463';
  return '#216e39';
}

export default function StreakDisplay({
  currentStreak, longestStreak, freezesRemaining, activityDays,
}: StreakDisplayProps) {
  const activeDatesSet = new Set(activityDays);

  // Generate last 12 weeks of dates for the heatmap
  const today = new Date();
  const weeks: Date[][] = [];
  for (let w = 11; w >= 0; w--) {
    const week: Date[] = [];
    for (let d = 0; d < 7; d++) {
      const date = new Date(today);
      date.setDate(today.getDate() - (w * 7 + (6 - d)));
      week.push(date);
    }
    weeks.push(week);
  }

  return (
    <Box>
      <Box display="flex" alignItems="center" gap={2} mb={2}>
        <Box display="flex" alignItems="center" gap={0.5}>
          <LocalFireDepartment
            sx={{ color: currentStreak > 0 ? '#ff6b35' : '#bdbdbd', fontSize: 32 }}
          />
          <Typography variant="h4" fontWeight={800} color={currentStreak > 0 ? '#ff6b35' : 'text.secondary'}>
            {currentStreak}
          </Typography>
          <Typography variant="body2" color="text.secondary" ml={0.5}>
            day streak
          </Typography>
        </Box>

        <Chip label={`Best: ${longestStreak}`} size="small" variant="outlined" />

        {freezesRemaining > 0 && (
          <Tooltip title={`${freezesRemaining} streak freeze${freezesRemaining > 1 ? 's' : ''} available`}>
            <Chip icon={<AcUnit />} label={freezesRemaining} size="small" color="info" />
          </Tooltip>
        )}
      </Box>

      {/* Activity heatmap */}
      <Box display="flex" gap="3px">
        {weeks.map((week, wi) => (
          <Box key={wi} display="flex" flexDirection="column" gap="3px">
            {week.map((day, di) => {
              const iso = day.toISOString().split('T')[0];
              const isActive = activeDatesSet.has(iso);
              return (
                <Tooltip key={di} title={`${iso}: ${isActive ? 'Active' : 'Inactive'}`}>
                  <Box
                    sx={{
                      width: 12,
                      height: 12,
                      borderRadius: '2px',
                      bgcolor: getHeatmapColor(isActive ? 1 : 0),
                    }}
                  />
                </Tooltip>
              );
            })}
          </Box>
        ))}
      </Box>
    </Box>
  );
}

import { Box, Typography, Button, Paper, Chip } from '@mui/material';
import { CheckCircle, Lock, CardGiftcard } from '@mui/icons-material';

interface DailyReward {
  day: number;
  xp: number;
  label: string;
  badge?: string;
}

interface DailyRewardCalendarProps {
  rewards: DailyReward[];
  currentDay: number;      // which day in the cycle (1-7)
  claimedToday: boolean;
  onClaim: () => void;
}

export default function DailyRewardCalendar({
  rewards, currentDay, claimedToday, onClaim,
}: DailyRewardCalendarProps) {
  return (
    <Box>
      <Typography variant="h6" gutterBottom>Daily Rewards</Typography>
      <Box display="flex" gap={1} flexWrap="wrap">
        {rewards.map((reward) => {
          const isClaimed = reward.day < currentDay || (reward.day === currentDay && claimedToday);
          const isAvailable = reward.day === currentDay && !claimedToday;
          const isLocked = reward.day > currentDay;

          return (
            <Paper
              key={reward.day}
              sx={{
                p: 2,
                minWidth: 100,
                textAlign: 'center',
                border: isAvailable ? '2px solid #ffd700' : '1px solid #e0e0e0',
                bgcolor: isClaimed ? '#f0fff0' : isAvailable ? '#fffde7' : '#fafafa',
                opacity: isLocked ? 0.6 : 1,
                transition: 'all 0.3s',
              }}
            >
              <Typography variant="caption" color="text.secondary">
                Day {reward.day}
              </Typography>
              <Box my={1}>
                {isClaimed ? (
                  <CheckCircle sx={{ color: '#4caf50', fontSize: 28 }} />
                ) : isLocked ? (
                  <Lock sx={{ color: '#bdbdbd', fontSize: 28 }} />
                ) : (
                  <CardGiftcard sx={{ color: '#ffd700', fontSize: 28 }} />
                )}
              </Box>
              <Chip label={`+${reward.xp} XP`} size="small" color={isClaimed ? 'success' : 'default'} />
              {reward.badge && (
                <Typography variant="caption" display="block" mt={0.5} color="warning.main">
                  + Badge!
                </Typography>
              )}
            </Paper>
          );
        })}
      </Box>
      {!claimedToday && (
        <Button
          variant="contained"
          color="warning"
          onClick={onClaim}
          sx={{ mt: 2, fontWeight: 700 }}
          startIcon={<CardGiftcard />}
        >
          Claim Day {currentDay} Reward
        </Button>
      )}
    </Box>
  );
}

from datetime import datetime, timedelta
from flask import Blueprint, request, g, jsonify
from models import db, XPTransaction, User, UserXP
from sqlalchemy import func, desc

leaderboard_bp = Blueprint("leaderboard", __name__)

PERIOD_DELTAS = {
    "daily": timedelta(days=1),
    "weekly": timedelta(weeks=1),
    "monthly": timedelta(days=30),
    "all_time": None,
}


@leaderboard_bp.route("/api/leaderboard")
def get_leaderboard():
    period = request.args.get("period", "weekly")
    limit = min(int(request.args.get("limit", 50)), 100)

    if period not in PERIOD_DELTAS:
        return jsonify({"error": "Invalid period"}), 400

    delta = PERIOD_DELTAS[period]

    if delta:
        since = datetime.utcnow() - delta
        # Sum XP earned in the time period
        query = (
            db.session.query(
                XPTransaction.user_id,
                func.sum(XPTransaction.amount).label("score"),
                func.rank().over(order_by=func.sum(XPTransaction.amount).desc()).label("rank"),
            )
            .filter(XPTransaction.created_at >= since)
            .group_by(XPTransaction.user_id)
            .order_by(desc("score"))
        )
    else:
        # All-time uses total_xp from user_xp table
        query = (
            db.session.query(
                UserXP.user_id,
                UserXP.total_xp.label("score"),
                func.rank().over(order_by=UserXP.total_xp.desc()).label("rank"),
            )
            .order_by(desc("score"))
        )

    # Get top N
    results = query.limit(limit).all()
    user_ids = [r.user_id for r in results]
    users = {u.id: u for u in User.query.filter(User.id.in_(user_ids)).all()}
    user_xp_map = {ux.user_id: ux for ux in UserXP.query.filter(UserXP.user_id.in_(user_ids)).all()}

    leaderboard = []
    for r in results:
        u = users.get(r.user_id)
        ux = user_xp_map.get(r.user_id)
        if u:
            leaderboard.append({
                "rank": r.rank,
                "user_id": r.user_id,
                "username": u.username,
                "avatar_url": u.avatar_url,
                "score": r.score,
                "level": ux.level if ux else 1,
            })

    # Always include the requesting user's rank
    my_rank = None
    if hasattr(g, "user_id") and g.user_id:
        my_entry = next((e for e in leaderboard if e["user_id"] == g.user_id), None)
        if my_entry:
            my_rank = my_entry
        else:
            # User not in top N — find their rank
            all_results = query.subquery()
            user_rank = (
                db.session.query(all_results)
                .filter(all_results.c.user_id == g.user_id)
                .first()
            )
            if user_rank:
                me = User.query.get(g.user_id)
                my_xp = UserXP.query.get(g.user_id)
                my_rank = {
                    "rank": user_rank.rank,
                    "user_id": g.user_id,
                    "username": me.username if me else "You",
                    "score": user_rank.score,
                    "level": my_xp.level if my_xp else 1,
                }

    return jsonify({
        "period": period,
        "leaderboard": leaderboard,
        "my_rank": my_rank,
    })

