import {
  Box, Typography, Paper, LinearProgress, Button, Chip, Stack,
} from '@mui/material';
import { CheckCircle, Timer, EmojiEvents } from '@mui/icons-material';

interface QuestData {
  questId: number;
  title: string;
  description: string;
  target: number;
  progress: number;
  xpReward: number;
  completedAt: string | null;
  expiresAt: string;
}

interface QuestPanelProps {
  quests: QuestData[];
  onClaimReward: (questId: number) => void;
}

function timeRemaining(expiresAt: string): string {
  const diff = new Date(expiresAt).getTime() - Date.now();
  if (diff <= 0) return 'Expired';
  const hours = Math.floor(diff / 3600000);
  const mins = Math.floor((diff % 3600000) / 60000);
  return `${hours}h ${mins}m remaining`;
}

export default function QuestPanel({ quests, onClaimReward }: QuestPanelProps) {
  return (
    <Box>
      <Typography variant="h6" gutterBottom>
        Daily Quests
      </Typography>
      <Stack spacing={2}>
        {quests.map((quest) => {
          const isComplete = quest.completedAt !== null;
          const pct = Math.min((quest.progress / quest.target) * 100, 100);

          return (
            <Paper key={quest.questId} sx={{ p: 2 }}>
              <Box display="flex" justifyContent="space-between" alignItems="flex-start">
                <Box flex={1}>
                  <Box display="flex" alignItems="center" gap={1} mb={0.5}>
                    {isComplete ? (
                      <CheckCircle sx={{ color: '#4caf50' }} />
                    ) : (
                      <EmojiEvents sx={{ color: '#ff9800' }} />
                    )}
                    <Typography variant="subtitle2" fontWeight={700}>
                      {quest.title}
                    </Typography>
                  </Box>
                  <Typography variant="body2" color="text.secondary" mb={1}>
                    {quest.description}
                  </Typography>
                  <LinearProgress
                    variant="determinate"
                    value={pct}
                    sx={{ height: 8, borderRadius: 4, mb: 0.5 }}
                    color={isComplete ? 'success' : 'primary'}
                  />
                  <Box display="flex" justifyContent="space-between">
                    <Typography variant="caption" color="text.secondary">
                      {quest.progress} / {quest.target}
                    </Typography>
                    {!isComplete && (
                      <Typography variant="caption" color="text.secondary">
                        <Timer sx={{ fontSize: 12, mr: 0.5, verticalAlign: 'middle' }} />
                        {timeRemaining(quest.expiresAt)}
                      </Typography>
                    )}
                  </Box>
                </Box>
                <Box ml={2} textAlign="center">
                  <Chip label={`+${quest.xpReward} XP`} size="small" color="warning" />
                  {isComplete && (
                    <Button size="small" variant="contained" color="success" sx={{ mt: 1 }} onClick={() => onClaimReward(quest.questId)}>
                      Claim
                    </Button>
                  )}
                </Box>
              </Box>
            </Paper>
          );
        })}
      </Stack>
    </Box>
  );
}

import {
  Box, Typography, LinearProgress, List, ListItem,
  ListItemIcon, ListItemText, Chip,
} from '@mui/material';
import { CheckCircle, RadioButtonUnchecked } from '@mui/icons-material';

interface ProfileField {
  key: string;
  label: string;
  weight: number;  // percentage points
  completed: boolean;
}

interface ProfileCompletionBarProps {
  fields: ProfileField[];
}

const DEFAULT_FIELDS: ProfileField[] = [
  { key: 'avatar', label: 'Upload a profile photo', weight: 20, completed: false },
  { key: 'bio', label: 'Write a short bio', weight: 15, completed: false },
  { key: 'location', label: 'Add your location', weight: 10, completed: false },
  { key: 'website', label: 'Link your website', weight: 10, completed: false },
  { key: 'skills', label: 'Add at least 3 skills', weight: 15, completed: false },
  { key: 'social', label: 'Connect a social account', weight: 10, completed: false },
  { key: 'first_post', label: 'Create your first post', weight: 20, completed: false },
];

export default function ProfileCompletionBar({ fields = DEFAULT_FIELDS }: ProfileCompletionBarProps) {
  const percentage = fields.reduce((sum, f) => sum + (f.completed ? f.weight : 0), 0);
  const incomplete = fields.filter((f) => !f.completed);

  const color = percentage >= 80 ? 'success' : percentage >= 50 ? 'warning' : 'error';

  return (
    <Box>
      <Box display="flex" justifyContent="space-between" alignItems="center" mb={1}>
        <Typography variant="subtitle1" fontWeight={700}>
          Profile Strength
        </Typography>
        <Chip label={`${percentage}%`} color={color} size="small" />
      </Box>
      <LinearProgress
        variant="determinate"
        value={percentage}
        color={color}
        sx={{ height: 10, borderRadius: 5, mb: 2 }}
      />
      {incomplete.length > 0 && (
        <>
          <Typography variant="body2" color="text.secondary" gutterBottom>
            Complete these to strengthen your profile:
          </Typography>
          <List dense>
            {incomplete.map((field) => (
              <ListItem key={field.key} disablePadding sx={{ mb: 0.5 }}>
                <ListItemIcon sx={{ minWidth: 32 }}>
                  <RadioButtonUnchecked sx={{ fontSize: 18, color: '#bdbdbd' }} />
                </ListItemIcon>
                <ListItemText
                  primary={field.label}
                  secondary={`+${field.weight}%`}
                  primaryTypographyProps={{ variant: 'body2' }}
                />
              </ListItem>
            ))}
          </List>
        </>
      )}
      {percentage === 100 && (
        <Box display="flex" alignItems="center" gap={1} color="success.main">
          <CheckCircle />
          <Typography variant="body2" fontWeight={700}>
            Profile complete! You earned +50 XP.
          </Typography>
        </Box>
      )}
    </Box>
  );
}

